SELECT * FROM follow_up_visit 
WHERE contract_id = #{contractId}
ORDER BY visit_date DESC

SELECT * FROM follow_up_visit 
WHERE visitor_user_id = #{visitorUserId}
ORDER BY visit_date DESC

SELECT * FROM follow_up_visit 
WHERE 1=1

    AND contract_id = #{contractId}


    AND visitor_user_id = #{visitorUserId}


    AND visit_date >= #{startDate}


    AND visit_date <= #{endDate}

ORDER BY visit_date DESC

SELECT * FROM follow_up_visit 
WHERE visit_date BETWEEN #{startDate} AND #{endDate}
ORDER BY visit_date DESC

SELECT * FROM follow_up_visit 
ORDER BY visit_date DESC
LIMIT #{limit}

SELECT * FROM follow_up_visit 
WHERE satisfaction >= #{minSatisfaction}
ORDER BY satisfaction DESC, visit_date DESC

